detection_pack.kql:
// ================================================================
// KQL — Microsoft Sentinel / Defender XDR
// APEX Advisory: Kazuar Malware Evolves Into Modular Espionage Ecosystem for 
// CVE: Kazuar Malware Evolv | Class: GENERIC_CVE | APEX v161.0
// Generated: 2026-05-25
// ================================================================

let lookback = 30d;

// IOC-based hunt — network events
let apex_iocs = dynamic(["436cfce71290c2fc2f2c362541db68ced6847c66a73b55487e5e5c73b0636c85", "69908f05b436bd97baae56296bf9b9e734486516f9bb9938c2b8752e152315d4", "6eb31006ca318a21eb619d008226f08e287f753aec9042269203290462eaa00d", "c1f278f88275e07cc03bd390fe1cbeedd55933110c6fd16de4187f4c4aaf42b9"]);
DeviceNetworkEvents
| where Timestamp > ago(lookback)
| where RemoteUrl has_any (apex_iocs) or RemoteIP has_any (apex_iocs)
| extend Severity = "High", Rule = "APEX-Kazuar Malware Evolv-IOC"
| project Timestamp, DeviceName, RemoteUrl, RemoteIP, InitiatingProcessFileName, Severity, Rule
| order by Timestamp desc;


// Alert rule: SecurityAlert table correlation
SecurityAlert
| where TimeGenerated > ago(lookback)
| where AlertName contains "Kazuar Malware Evolv" or Description contains "Kazuar Malware Evolv"
| extend Rule = "APEX-Kazuar Malware Evolv-ALERT"
| project TimeGenerated, AlertName, AlertSeverity, Entities, Description, Rule
| order by TimeGenerated desc;

